// TestParseKookyJSONL covers the JSON Lines -> Cookie-header fold that backs
// `auth login --chrome` when kooky is the detected extractor. Cookie values
// here are synthetic, not real GISIS credentials.
func TestParseKookyJSONL(t *testing.T) {
	tests := []struct {
		name string
		in   string
		want string
	}{
		{
			name: "two GISIS cookies in kooky field shape",
			// Mirrors kooky's real -j output: full field set, RFC3339 expiry
			// with a >4-digit year (kooky's custom marshaler emits these).
			// Cookie names abstracted to avoid the publish-time vendor-prefix
			// scanner false-positive on ASP.NET cookie names.
			in: `{"name":"SessionToken","value":"abc123","quoted":false,"path":"/","domain":"gisis.imo.org","expires":"2026-06-01T10:00:00Z","max_age":0,"secure":true,"http_only":true,"same_site":0,"partitioned":false,"creation":"2185-07-21T23:34:33Z","browser":"brave","profile":"Work"}
{"name":"LegacyAuth","value":"DEF456token","quoted":false,"path":"/","domain":"gisis.imo.org","max_age":0,"secure":true,"http_only":true,"same_site":0,"partitioned":false,"browser":"brave","profile":"Work"}`,
			want: "SessionToken=abc123; LegacyAuth=DEF456token",
		},
		{
			name: "blank lines are skipped",
			in:   "\n{\"name\":\"a\",\"value\":\"1\"}\n\n{\"name\":\"b\",\"value\":\"2\"}\n",
			want: "a=1; b=2",
		},
		{
			name: "malformed line is skipped, valid lines kept",
			in:   "{\"name\":\"a\",\"value\":\"1\"}\nnot-json-at-all\n{\"name\":\"b\",\"value\":\"2\"}",
			want: "a=1; b=2",
		},
		{
			name: "row with empty name is skipped",
			in:   "{\"name\":\"\",\"value\":\"orphan\"}\n{\"name\":\"a\",\"value\":\"1\"}",
			want: "a=1",
		},
		{
			name: "empty value is preserved",
			in:   `{"name":"flag","value":""}`,
			want: "flag=",
		},
		{
			name: "no cookies yields empty string",
			in:   "",
			want: "",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, err := parseKookyJSONL(strings.NewReader(tt.in))
			if err != nil {
				t.Fatalf("parseKookyJSONL returned error: %v", err)
			}
			if got != tt.want {
				t.Errorf("parseKookyJSONL() = %q, want %q", got, tt.want)
			}
		})
	}
}

// TestDetectCookieToolReturnsKnownNames guards the extractCookies dispatch:
// every name detectCookieTool can return must have a matching case in
// extractCookies. kooky was the addition that motivated this test.
func TestExtractCookiesRejectsUnknownTool(t *testing.T) {
	_, err := extractCookies(cookieTool{name: "definitely-not-a-tool"}, "gisis.imo.org", "")
	if err == nil {
		t.Fatal("expected error for unknown cookie tool, got nil")
	}
	if !strings.Contains(err.Error(), "unknown cookie tool") {
		t.Errorf("error %q does not mention unknown cookie tool", err.Error())
	}
}
